const input = $input.first().json;
const leadName = input.leadName || 'Lead';
const history = input.conversationHistory || [];
const profile = input.currentProfile;
const interests = input.currentInterests || [];

let historyStr = '';
for (const msg of history) {
  historyStr += `${msg.role === 'user' ? 'Cliente' : 'Assistente'}: ${msg.content}\n`;
}

let profileStr = '';
if (profile) {
  if (profile.investor_profile) profileStr += `- Perfil: ${profile.investor_profile}\n`;
  if (profile.goal) profileStr += `- Objetivo: ${profile.goal}\n`;
}

let interestsStr = '';
for (const int of interests) {
  interestsStr += `- ${int.interest_type}\n`;
}

const systemPrompt = `Voce e um assistente de qualificacao de leads da KEA Wealth Management. Conduza uma conversa natural, apresente os servicos, extraia dados do lead. Responda APENAS com JSON: {"message":"resposta","stage":"welcome|presentation|investor_profile|financial_goal|qualification","extractedData":{"name":null,"interest":null,"investor_profile":null,"goal":null,"monthly_value":null},"qualified":false,"qualificationScore":0,"action":"continue|generate_proposal"}. Score: investor_profile=2, monthly_value=3, interest=1, goal=1. Min 4 pts para qualificar.`;

const userPrompt = `Historico:\n${historyStr}\nPerfil: ${profileStr}\nInteresses: ${interestsStr}\nMensagem de ${leadName}:\n${input.message}`;

const httpReq = await $http.post('https://api.deepseek.com/v1/chat/completions', {
  model: 'deepseek-chat',
  temperature: 0.7,
  max_tokens: 1000,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
}, {
  headers: { Authorization: 'Bearer sk-948dd4228f944335bf1597c161a1fda1' }
});

const content = httpReq.choices[0].message.content;
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = { message: content, stage: 'conversation', extractedData: {}, qualified: false, qualificationScore: 0, action: 'continue' };
}

return {
  message: parsed.message,
  stage: parsed.stage || 'conversation',
  qualified: parsed.qualified || false,
  qualificationScore: parsed.qualificationScore || 0,
  action: parsed.action || 'continue',
  extractedData: parsed.extractedData || {},
  metadata: { leadId: input.leadId, phone: input.phone }
};
